baseStyle.backgroundColor = upperColor.includes('NAVY') ? '#2d3748' : '#1A202C';
baseStyle.color = '#FFFFFF';
} else {
baseStyle.backgroundColor = '#FFFFFF';
baseStyle.color = '#1A202C';
baseStyle.border = '1px solid var(--skeleton-bg)';
}
return baseStyle;
};

